package com.meituan.route.model;

import java.time.LocalTime;
import java.util.List;

/**
 * Point of Interest - a location that can be visited in a route.
 */
public record POI(
        String id,
        String name,
        String category,       // RESTAURANT, ATTRACTION, SHOPPING, ENTERTAINMENT, CULTURE
        String subCategory,
        double lat,
        double lng,
        String address,
        String district,       // e.g. "三里屯", "国贸"
        String city,
        double rating,
        double avgCost,
        double queueTime,      // estimated queue time in minutes
        LocalTime openTime,
        LocalTime closeTime,
        int visitDuration,     // recommended stay in minutes
        List<String> tags,
        String imageUrl,
        String description,
        double popularityScore // 0-100
) {
    public boolean isOpenDuring(LocalTime start, LocalTime end) {
        return !start.isBefore(openTime) && !end.isAfter(closeTime);
    }

    public boolean matchesCategory(String cat) {
        return category.equalsIgnoreCase(cat) || tags.stream().anyMatch(t -> t.contains(cat));
    }
}

package com.meituan.route.model;

import java.time.LocalTime;
import java.util.List;

/**
 * A complete route plan consisting of ordered POI visits with timing.
 */
public record Route(
        String id,
        String name,
        String description,
        List<RouteSegment> segments,
        double totalCost,
        double totalTravelTime,   // minutes
        double totalRating,
        String optimizationGoal,  // BEST_EXPERIENCE, FASTEST, CHEAPEST
        List<Constraint> satisfiedConstraints,
        List<Constraint> violatedSoftConstraints,
        double score              // composite score for ranking
) {
    public record RouteSegment(
            POI poi,
            LocalTime arrivalTime,
            LocalTime departureTime,
            double travelTimeFromPrevious, // minutes; 0 for first POI
            String travelMode              // WALKING, DRIVING
    ) {
        public double duration() {
            return java.time.Duration.between(arrivalTime, departureTime).toMinutes();
        }
    }
}

package com.meituan.route.model;

import java.util.Optional;

/**
 * A constraint that a route must satisfy.
 */
public record Constraint(
        String id,
        ConstraintType type,
        Scope scope,
        double priority,        // higher = more important
        double weight,          // weight in scoring
        String description,
        Object value            // typed constraint value (parsed by engine)
) {
    public enum ConstraintType {
        HARD,   // must satisfy — pruning condition
        SOFT    // preference — scored
    }

    public enum Scope {
        GLOBAL,         // applies to whole route
        PER_POI,        // applies per individual POI
        ADJACENT_PAIR   // applies between consecutive POIs
    }

    @SuppressWarnings("unchecked")
    public <T> Optional<T> getValueAs(Class<T> clazz) {
        if (value != null && clazz.isInstance(value)) {
            return Optional.of((T) value);
        }
        return Optional.empty();
    }

    // Factory methods
    public static Constraint budget(double maxCost, double priority) {
        return new Constraint("budget", ConstraintType.SOFT, Scope.GLOBAL,
                priority, 0.3, "Budget limit: ¥" + maxCost, maxCost);
    }

    public static Constraint timeWindow(String start, String end, double priority) {
        return new Constraint("time_window", ConstraintType.HARD, Scope.GLOBAL,
                priority, 0.0, "Time window: " + start + " - " + end,
                java.util.List.of(java.time.LocalTime.parse(start), java.time.LocalTime.parse(end)));
    }

    public static Constraint minRating(double minRating, double priority) {
        return new Constraint("min_rating", ConstraintType.SOFT, Scope.PER_POI,
                priority, 0.2, "Minimum rating: " + minRating, minRating);
    }

    public static Constraint category(String category, double priority) {
        return new Constraint("category", ConstraintType.HARD, Scope.PER_POI,
                priority, 0.0, "Category: " + category, category);
    }

    public static Constraint maxQueue(int maxMinutes, double priority) {
        return new Constraint("max_queue", ConstraintType.SOFT, Scope.PER_POI,
                priority, 0.15, "Max queue: " + maxMinutes + " min", (double) maxMinutes);
    }

    public static Constraint travelMode(String mode, double priority) {
        return new Constraint("travel_mode", ConstraintType.SOFT, Scope.ADJACENT_PAIR,
                priority, 0.1, "Travel mode: " + mode, mode);
    }
}

package com.meituan.route.model;

import java.time.LocalTime;
import java.util.List;
import java.util.Optional;

/**
 * Structured user intent parsed from natural language.
 */
public record UserIntent(
        String rawQuery,
        String city,
        String district,
        List<String> preferredCategories,
        String cuisinePreference,
        LocalTime startTime,
        LocalTime endTime,
        double budget,
        int partySize,
        double minRating,
        int maxQueueMinutes,
        String travelMode,       // WALKING, DRIVING
        String optimizationGoal, // BEST_EXPERIENCE, FASTEST, CHEAPEST
        String specialRequest,   // e.g. "拍照好看", "少走路"
        List<String> keywords,
        String sessionId
) {
    // Validate and return missing fields
    public List<String> missingFields() {
        return List.of();
    }

    public Optional<String> optimizationGoal() {
        return Optional.ofNullable(optimizationGoal);
    }
}

