package com.meituan.route.llm;

import com.meituan.route.model.UserIntent;
import com.meituan.route.model.POI;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

import java.time.LocalTime;
import java.util.*;
import java.util.regex.Pattern;

/**
 * Parses natural language user queries into structured UserIntent.
 * Uses LangChain4j for LLM-based parsing when available,
 * falls back to pattern-matching when LLM is not configured.
 */
@Component
public class IntentParser {

    private static final Logger log = LoggerFactory.getLogger(IntentParser.class);

    private static final Pattern CHINESE_NUM = Pattern.compile("[一二两三四五六七八九十百]+");

    // Common time patterns
    private static final Map<String, String> TIME_KEYWORDS = Map.ofEntries(
            Map.entry("早上", "08:00"), Map.entry("上午", "09:00"),
            Map.entry("中午", "12:00"), Map.entry("下午", "14:00"),
            Map.entry("傍晚", "17:00"), Map.entry("晚上", "18:00"),
            Map.entry("夜间", "20:00"), Map.entry("半夜", "22:00"),
            Map.entry("全天", "08:00"), Map.entry("周末", "10:00")
    );

    // Category keywords
    private static final Map<String, String> CATEGORY_MAP = Map.ofEntries(
            Map.entry("逛街", "SHOPPING"), Map.entry("购物", "SHOPPING"), Map.entry("商场", "SHOPPING"),
            Map.entry("吃", "RESTAURANT"), Map.entry("餐厅", "RESTAURANT"), Map.entry("美食", "RESTAURANT"),
            Map.entry("日料", "RESTAURANT"), Map.entry("火锅", "RESTAURANT"), Map.entry("烤鸭", "RESTAURANT"),
            Map.entry("景点", "ATTRACTION"), Map.entry("玩", "ATTRACTION"), Map.entry("公园", "ATTRACTION"),
            Map.entry("电影", "ENTERTAINMENT"), Map.entry("酒吧", "ENTERTAINMENT"), Map.entry("娱乐", "ENTERTAINMENT"),
            Map.entry("文化", "CULTURE"), Map.entry("博物馆", "CULTURE"), Map.entry("书店", "CULTURE"),
            Map.entry("艺术", "CULTURE")
    );

    // District keywords
    private static final Map<String, String> DISTRICT_MAP = Map.ofEntries(
            Map.entry("三里屯", "三里屯"), Map.entry("国贸", "国贸"),
            Map.entry("王府井", "王府井"), Map.entry("前门", "前门"),
            Map.entry("东城", "东城"), Map.entry("西城", "西城"),
            Map.entry("外滩", "外滩"), Map.entry("陆家嘴", "陆家嘴"),
            Map.entry("新天地", "新天地"), Map.entry("南京路", "南京路"),
            Map.entry("静安寺", "静安寺"), Map.entry("浦东", "浦东"),
            Map.entry("海淀", "海淀"), Map.entry("朝阳", "三里屯")
    );

    // Budget and rating patterns
    private static final Pattern BUDGET_PATTERN = Pattern.compile("预算(\\d+)");
    private static final Pattern RATING_PATTERN = Pattern.compile("评分[以至少高于大于等于]*([\\d.]+)");
    private static final Pattern CUISINE_PATTERN = Pattern.compile("(日料|火锅|烤鸭|西餐|川菜|湘菜|云南菜|上海菜|北京菜|粤菜|咖啡|奶茶|甜品)");

    public IntentParser() {
        log.info("IntentParser initialized (rule-based fallback mode)");
    }

    /**
     * Parse a natural language query into a structured UserIntent.
     * Step 1: Try LLM-based parsing (if configured).
     * Step 2: Fall back to rule-based parser.
     */
    public UserIntent parse(String query, String sessionId) {
        if (query == null || query.isBlank()) {
            throw new IllegalArgumentException("Query cannot be empty");
        }

        // Use enhanced rule-based parsing
        return parseWithRules(query, sessionId);
    }

    private UserIntent parseWithRules(String query, String sessionId) {
        String city = detectCity(query);
        String district = detectDistrict(query);
        var categories = detectCategories(query);
        String cuisine = detectCuisine(query);
        var times = detectTimeRange(query);
        double budget = detectBudget(query);
        double minRating = detectRating(query);
        int maxQueue = detectQueueTolerance(query);
        String travelMode = detectTravelMode(query);
        String goal = detectGoal(query, categories);
        List<String> keywords = extractKeywords(query);

        return new UserIntent(
                query, city, district, categories, cuisine,
                times[0], times[1], budget, 2, minRating,
                maxQueue, travelMode, goal, null, keywords, sessionId
        );
    }

    private String detectCity(String query) {
        if (query.contains("北京") || query.contains("三里屯") || query.contains("国贸")
                || query.contains("王府井") || query.contains("海淀")) return "北京";
        if (query.contains("上海") || query.contains("外滩") || query.contains("陆家嘴")
                || query.contains("新天地") || query.contains("浦东")) return "上海";
        return "北京";
    }

    private String detectDistrict(String query) {
        return DISTRICT_MAP.entrySet().stream()
                .filter(e -> query.contains(e.getKey()))
                .map(Map.Entry::getValue)
                .findFirst()
                .orElse(null);
    }

    private List<String> detectCategories(String query) {
        var cats = new LinkedHashSet<String>();
        // Check for explicit sequence markers: "然后", "再", "之后", "接着"
        boolean hasSequence = Pattern.compile("然后|再|之后|接着").matcher(query).find();

        CATEGORY_MAP.forEach((keyword, category) -> {
            if (query.contains(keyword)) {
                cats.add(category);
            }
        });

        // If no explicit categories detected but query references eating/going out
        if (cats.isEmpty()) {
            if (query.contains("去") || query.contains("到") || query.contains("逛")) {
                cats.add("ATTRACTION");
                cats.add("RESTAURANT");
            }
        }

        return new ArrayList<>(cats);
    }

    private String detectCuisine(String query) {
        var matcher = CUISINE_PATTERN.matcher(query);
        if (matcher.find()) {
            return matcher.group(1);
        }
        return null;
    }

    private LocalTime[] detectTimeRange(String query) {
        LocalTime start = LocalTime.of(14, 0); // default afternoon
        LocalTime end = LocalTime.of(21, 0);   // default evening

        for (var entry : TIME_KEYWORDS.entrySet()) {
            if (query.contains(entry.getKey())) {
                start = LocalTime.parse(entry.getValue());
                break;
            }
        }

        // Adjust end time based on start
        if (start.isBefore(LocalTime.of(12, 0))) {
            end = LocalTime.of(17, 0);
        } else if (start.isBefore(LocalTime.of(17, 0))) {
            end = LocalTime.of(22, 0);
        }

        return new LocalTime[]{start, end};
    }

    private double detectBudget(String query) {
        var matcher = BUDGET_PATTERN.matcher(query);
        if (matcher.find()) {
            return Double.parseDouble(matcher.group(1));
        }
        return 0;
    }

    private double detectRating(String query) {
        var matcher = RATING_PATTERN.matcher(query);
        if (matcher.find()) {
            return Double.parseDouble(matcher.group(1));
        }
        return 3.5; // default minimum rating
    }

    private int detectQueueTolerance(String query) {
        if (query.contains("不排队") || query.contains("少排队")) return 10;
        if (query.contains("快") || query.contains("效率")) return 15;
        return 30; // default tolerance
    }

    private String detectTravelMode(String query) {
        if (query.contains("开车") || query.contains("驾车") || query.contains("滴滴")) return "DRIVING";
        if (query.contains("走路") || query.contains("步行")) return "WALKING";
        if (query.contains("少走路")) return "WALKING";
        return "WALKING";
    }

    private String detectGoal(String query, List<String> categories) {
        if (query.contains("省钱") || query.contains("便宜") || query.contains("划算")) return "CHEAPEST";
        if (query.contains("省时") || query.contains("快") || query.contains("效率")) return "FASTEST";
        return "BEST_EXPERIENCE";
    }

    private List<String> extractKeywords(String query) {
        var keywords = new ArrayList<String>();
        if (query.contains("拍照")) keywords.add("拍照好看");
        if (query.contains("约会")) keywords.add("约会");
        if (query.contains("亲子") || query.contains("带娃") || query.contains("带孩子")) keywords.add("亲子");
        if (query.contains("网红")) keywords.add("网红");
        return keywords;
    }
}

package com.meituan.route.llm;

import com.meituan.route.model.POI;
import com.meituan.route.model.Route;
import org.springframework.stereotype.Component;

import java.util.*;
import java.util.stream.Collectors;

/**
 * Generates natural language explanations and recommendations for routes.
 */
@Component
public class RecommendationExplainer {

    private static final Map<String, List<String>> TAG_PRAISE = Map.ofEntries(
            Map.entry("拍照好看", List.of("ins风出片圣地", "随手一拍就是大片", "朋友圈素材+1")),
            Map.entry("约会", List.of("浪漫指数爆表", "约会必去", "氛围感满分")),
            Map.entry("亲子", List.of("遛娃好去处", "孩子玩到不想走")),
            Map.entry("网红", List.of("小红书爆款", "排队也值得", "顶流打卡地")),
            Map.entry("历史", List.of("穿越时空的对话", "感受历史厚重感")),
            Map.entry("文化", List.of("文化熏陶之旅", "涨知识的好地方")),
            Map.entry("美食", List.of("味蕾的极致享受", "吃货的天堂")),
            Map.entry("排队", List.of("人气爆棚", "口碑之选")),
            Map.entry("免费", List.of("性价比之王", "不花钱的快乐"))
    );

    /**
     * Generate a detailed explanation for a single route.
     */
    public String explainRoute(Route route) {
        var sb = new StringBuilder();
        sb.append("## ").append(route.name()).append("\n\n");
        sb.append(route.description()).append("\n\n");
        sb.append("### 行程详情\n\n");

        for (int i = 0; i < route.segments().size(); i++) {
            var seg = route.segments().get(i);
            var poi = seg.poi();

            sb.append("**").append(i + 1).append(". ")
                    .append(poi.name()).append("**\n");
            sb.append("- 到达时间：").append(seg.arrivalTime()).append("\n");
            sb.append("- 离开时间：").append(seg.departureTime()).append("\n");
            sb.append("- 推荐理由：").append(generateReason(poi)).append("\n");
            sb.append("- 预计花费：¥").append(String.format("%.0f", poi.avgCost())).append("\n");
            sb.append("- 用户评分：").append(poi.rating()).append("\n");

            if (i < route.segments().size() - 1) {
                sb.append("- 前往下一站：步行约")
                        .append(String.format("%.0f", seg.travelTimeFromPrevious()))
                        .append("分钟\n");
            }
            sb.append("\n");
        }

        sb.append("### 费用汇总\n\n");
        sb.append("- 总花费：¥").append(String.format("%.0f", route.totalCost())).append("\n");
        sb.append("- 总步行时间：约").append(String.format("%.0f", route.totalTravelTime())).append("分钟\n");
        sb.append("- 综合评分：").append(String.format("%.1f",
                route.totalRating() / route.segments().size())).append("/5.0\n");

        return sb.toString();
    }

    /**
     * Generate a comparison of multiple routes.
     */
    public String compareRoutes(List<Route> routes) {
        if (routes.isEmpty()) return "暂无可用方案";
        if (routes.size() == 1) return explainRoute(routes.get(0));

        var sb = new StringBuilder();
        sb.append("# 路线方案对比\n\n");
        sb.append("为您生成了 **").append(routes.size()).append("** 个方案：\n\n");

        for (int i = 0; i < routes.size(); i++) {
            var route = routes.get(i);
            sb.append("### 🚀 方案").append(i + 1).append("：").append(route.name()).append("\n\n");

            var poiNames = route.segments().stream()
                    .map(s -> s.poi().name())
                    .collect(Collectors.joining(" → "));
            sb.append("路线：").append(poiNames).append("\n\n");

            sb.append("- 💰 费用：¥").append(String.format("%.0f", route.totalCost())).append("\n");
            sb.append("- ⭐ 均分：").append(String.format("%.1f",
                    route.totalRating() / route.segments().size())).append("\n");
            sb.append("- 🚶 路程：约").append(String.format("%.0f", route.totalTravelTime())).append("分钟\n\n");

            // Main reason
            sb.append("**推荐理由：** ").append(generateRouteReason(route)).append("\n\n");
            sb.append("---\n\n");
        }

        // Final recommendation
        var best = routes.get(0);
        sb.append("### 💡 小编推荐\n\n");
        sb.append("推荐 **").append(best.name()).append("**：");
        sb.append(generateRouteReason(best)).append("\n");

        return sb.toString();
    }

    private String generateReason(POI poi) {
        var reasons = new ArrayList<String>();

        if (poi.rating() >= 4.5) {
            reasons.add("评分高达" + poi.rating() + "分");
        }

        for (var tag : poi.tags()) {
            var praises = TAG_PRAISE.get(tag);
            if (praises != null && !praises.isEmpty()) {
                reasons.add(praises.get(new Random().nextInt(praises.size())));
            }
        }

        if (reasons.isEmpty()) {
            reasons.add(poi.description());
        }

        return String.join("，", reasons);
    }

    private String generateRouteReason(Route route) {
        return switch (route.optimizationGoal()) {
            case "BEST_EXPERIENCE" -> "精选高评分POI，体验最佳，适合享受型的您";
            case "FASTEST" -> "路线最紧凑高效，省时省力，适合时间紧张的你";
            case "CHEAPEST" -> "严格控制预算，性价比之选，花少钱玩尽兴";
            default -> route.segments().size() + "个地点串联，合理规划时间";
        };
    }
}

package com.meituan.route.state;

import com.meituan.route.model.Route;
import com.meituan.route.model.UserIntent;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Manages session state for multi-turn conversation.
 * Stores route planning snapshots for incremental adjustments.
 */
@Component
public class SessionStateManager {

    private final Map<String, Session> sessions = new ConcurrentHashMap<>();

    /**
     * Create a new session and return its ID.
     */
    public String createSession() {
        String id = "sess_" + UUID.randomUUID().toString().substring(0, 8);
        sessions.put(id, new Session(id, new ArrayList<>(), null, Instant.now(), Instant.now()));
        return id;
    }

    /**
     * Get session by ID.
     */
    public Optional<Session> getSession(String sessionId) {
        return Optional.ofNullable(sessions.get(sessionId));
    }

    /**
     * Store a route snapshot for a session.
     */
    public void addSnapshot(String sessionId, Route route, UserIntent intent) {
        var session = sessions.get(sessionId);
        if (session != null) {
            var newSnapshots = new ArrayList<>(session.snapshots());
            newSnapshots.add(new Snapshot(newSnapshots.size() + 1, route, intent, Instant.now()));
            var updated = new Session(sessionId, newSnapshots, intent, session.createdAt(), Instant.now());
            sessions.put(sessionId, updated);
        }
    }

    /**
     * Update the latest intent for a session.
     */
    public void updateIntent(String sessionId, UserIntent intent) {
        var session = sessions.get(sessionId);
        if (session != null) {
            sessions.put(sessionId, new Session(sessionId, session.snapshots(), intent,
                    session.createdAt(), Instant.now()));
        }
    }

    /**
     * Get the latest route for a session.
     */
    public Optional<Route> getLatestRoute(String sessionId) {
        return getSession(sessionId)
                .map(Session::snapshots)
                .filter(s -> !s.isEmpty())
                .map(s -> s.get(s.size() - 1).route());
    }

    /**
     * Get all routes for a session.
     */
    public List<Route> getAllRoutes(String sessionId) {
        return getSession(sessionId)
                .map(Session::snapshots)
                .orElse(List.of())
                .stream()
                .map(Snapshot::route)
                .toList();
    }

    /**
     * Handle adjustment: keep prefix, regenerate suffix.
     * Returns the number of POIs to keep from the front.
     */
    public int resolveAdjustment(String adjustment, Route currentRoute) {
        var adj = adjustment.toLowerCase();

        if (adj.contains("前面") || adj.contains("前几家")) {
            // Try to parse how many to keep
            if (adj.contains("都不")) return 0;
            if (adj.contains("一家") || adj.contains("一个")) return 1;
            if (adj.contains("两家") || adj.contains("两个")) return 2;
            return 1; // default: keep first
        }

        if (adj.contains("最后") || adj.contains("后面")) {
            if (adj.contains("一家") || adj.contains("一个")) {
                int segCount = currentRoute.segments().size();
                return segCount - 1; // keep all except last
            }
            return 0;
        }

        if (adj.contains("换成") || adj.contains("换")) {
            // Find which POI to replace
            for (int i = 0; i < currentRoute.segments().size(); i++) {
                var seg = currentRoute.segments().get(i);
                if (adj.contains(seg.poi().name()) || adj.contains(seg.poi().category())) {
                    return i; // keep up to this POI
                }
            }
            // Replace last POI of matching category
            return currentRoute.segments().size() - 1;
        }

        // Default: full re-plan
        return 0;
    }

    public record Session(
            String sessionId,
            List<Snapshot> snapshots,
            UserIntent currentIntent,
            Instant createdAt,
            Instant updatedAt
    ) {}

    public record Snapshot(
            int version,
            Route route,
            UserIntent intent,
            Instant timestamp
    ) {}
}

