import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

/**
 * ConversationAgent handles multi-turn dialogue, maintains session context,
 * and outputs a structured UserIntent.
 *
 * Responsibilities:
 * - Parse natural language queries into structured intents
 * - Maintain conversation history across turns
 * - Detect intent changes for incremental adjustments
 */
@Component
public class ConversationAgent {

    private static final Logger log = LoggerFactory.getLogger(ConversationAgent.class);

    private final IntentParser intentParser;
    private final SessionStateManager sessionManager;

    public ConversationAgent(IntentParser intentParser, SessionStateManager sessionManager) {
        this.intentParser = intentParser;
        this.sessionManager = sessionManager;
    }

    /**
     * Process a natural language request and produce a structured intent.
     * For new sessions, creates a fresh intent.
     * For existing sessions, merges the adjustment with prior context.
     */
    public ConversationResult process(String query, String sessionId) {
        log.info("ConversationAgent processing query: '{}' for session: {}", query, sessionId);

        String actualSessionId = sessionId;
        if (actualSessionId == null || actualSessionId.isBlank()) {
            actualSessionId = sessionManager.createSession();
            log.info("Created new session: {}", actualSessionId);
        }

        // Parse the query into intent
        var intent = intentParser.parse(query, actualSessionId);

        // Check if this is an adjustment to an existing session
        var existingSession = sessionManager.getSession(actualSessionId);
        boolean isAdjustment = existingSession.isPresent()
                && existingSession.get().snapshots() != null
                && !existingSession.get().snapshots().isEmpty();

        if (isAdjustment) {
            sessionManager.updateIntent(actualSessionId, intent);
        }

        // Detect adjustments keywords
        String adjustmentQuery = null;
        if (isAdjustment && isAdjustmentQuery(query)) {
            adjustmentQuery = query;
        }

        log.info("ConversationAgent produced intent: city={}, district={}, categories={}",
                intent.city(), intent.district(), intent.preferredCategories());

        return new ConversationResult(actualSessionId, intent, adjustmentQuery,
                existingSession.map(s -> s.currentIntent()).orElse(null));
    }

    private boolean isAdjustmentQuery(String query) {
        var adj = query.toLowerCase();
        return adj.contains("换") || adj.contains("改") || adj.contains("调整")
                || adj.contains("不要") || adj.contains("替换") || adj.contains("去掉");
    }

    /**
     * Result from ConversationAgent processing.
     */
    public record ConversationResult(
            String sessionId,
            UserIntent intent,
            String adjustmentQuery,
            UserIntent previousIntent
    ) {
        public boolean isAdjustment() {
            return adjustmentQuery != null;
        }
    }
}

package com.meituan.route.agent;

import com.meituan.route.data.DataService;
import com.meituan.route.model.POI;
import com.meituan.route.model.UserIntent;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;

import java.util.*;
import java.util.stream.Collectors;

/**
 * DiscoveryAgent receives a UserIntent and retrieves candidate POIs from the DataService.
 * Applies hard constraint filtering (time, category matching).
 */
@Component
public class DiscoveryAgent {

    private static final Logger log = LoggerFactory.getLogger(DiscoveryAgent.class);

    private final DataService dataService;

    public DiscoveryAgent(DataService dataService) {
        this.dataService = dataService;
    }

    /**
     * Discover candidate POIs based on user intent.
     * Uses parallel queries for different categories.
     */
    public Mono<DiscoveryResult> discover(UserIntent intent) {
        log.info("DiscoveryAgent searching for POIs in {} {} categories: {}",
                intent.city(), intent.district(), intent.preferredCategories());

        String city = intent.city() != null ? intent.city() : "北京";

        // If specific categories are provided, search by each in parallel
        List<String> categories = intent.preferredCategories();
        if (categories == null || categories.isEmpty()) {
            categories = List.of("RESTAURANT", "ATTRACTION", "SHOPPING", "ENTERTAINMENT", "CULTURE");
        }

        // Parallel search across categories using virtual threads
        var poiFluxes = categories.stream()
                .map(cat -> dataService.searchByCategory(city, intent.district(), cat))
                .toList();

        var allPOIs = Flux.merge(poiFluxes)
                .distinct(POI::id)
                .collectList()
                .flatMap(pois -> applyHardFilters(pois, intent));

        return allPOIs.map(pois -> {
            log.info("DiscoveryAgent found {} POIs after filtering", pois.size());
            return new DiscoveryResult(pois, categorizePOIs(pois), intent);
        });
    }

    /**
     * Apply hard constraints to filter candidates.
     */
    private Mono<List<POI>> applyHardFilters(List<POI> pois, UserIntent intent) {
        var filtered = pois.stream()
                .filter(poi -> {
                    // Budget filter (hard ceiling at 2x budget for flexibility)
                    if (intent.budget() > 0 && poi.avgCost() > intent.budget() * 2) {
                        return false;
                    }
                    return true;
                })
                .sorted(Comparator.<POI, Double>comparing(p -> -p.rating())
                        .thenComparing(p -> -p.popularityScore()))
                .limit(20) // Limit candidates for solver performance
                .toList();

        return Mono.just(filtered);
    }

    /**
     * Categorize POIs for easier processing by PlanningAgent.
     */
    private Map<String, List<POI>> categorizePOIs(List<POI> pois) {
        return pois.stream()
                .collect(Collectors.groupingBy(POI::category));
    }

    /**
     * Extract a user's special request keywords into POI tag filters.
     */
    public List<String> extractPreferenceTags(UserIntent intent) {
        var tags = new ArrayList<String>();
        if (intent.specialRequest() != null) {
            var req = intent.specialRequest();
            if (req.contains("拍照")) tags.add("拍照");
            if (req.contains("约会")) tags.add("约会");
            if (req.contains("安静")) tags.add("安静");
        }
        if (intent.keywords() != null) {
            tags.addAll(intent.keywords());
        }
        return tags;
    }

    public record DiscoveryResult(
            List<POI> candidates,
            Map<String, List<POI>> categorizedPOIs,
            UserIntent intent
    ) {}
}

package com.meituan.route.agent;

import com.meituan.route.model.Route;
import com.meituan.route.model.Constraint;
import com.meituan.route.model.UserIntent;
import com.meituan.route.solver.ConstraintEngine;
import com.meituan.route.solver.GraphSearchSolver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

import java.util.*;
import java.util.stream.Collectors;

/**
 * PlanningAgent receives candidate POIs, builds a POI connectivity graph,
 * and generates 2-3 differentiated route plans.
 */
@Component
public class PlanningAgent {

    private static final Logger log = LoggerFactory.getLogger(PlanningAgent.class);

    private final GraphSearchSolver graphSolver;
    private final ConstraintEngine constraintEngine;

    public PlanningAgent(GraphSearchSolver graphSolver, ConstraintEngine constraintEngine) {
        this.graphSolver = graphSolver;
        this.constraintEngine = constraintEngine;
    }

    /**
     * Generate route plans from discovered POIs and user intent.
     */
    public PlanningResult plan(DiscoveryAgent.DiscoveryResult discovery, UserIntent intent,
                               List<Constraint> additionalConstraints) {
        log.info("PlanningAgent generating plans from {} candidates with goal: {}",
                discovery.candidates().size(), intent.optimizationGoal());

        var candidates = discovery.candidates();
        if (candidates.isEmpty()) {
            log.warn("No candidates available for planning");
            return new PlanningResult(List.of(), "没有找到符合条件的POI，请调整搜索条件", intent);
        }

        // Build constraints from intent
        var constraints = new ArrayList<>(constraintEngine.buildConstraints(intent, candidates));
        if (additionalConstraints != null) {
            constraints.addAll(additionalConstraints);
        }

        // Generate plans (3 by default)
        var routes = graphSolver.generatePlans(candidates, constraints, intent, 3);

        if (routes.isEmpty()) {
            // Relax constraints and retry
            log.info("No initial solution, attempting constraint relaxation...");
            var relaxations = constraintEngine.relaxConstraints(constraints);

            for (var relaxed : relaxations) {
                routes = graphSolver.generatePlans(candidates, relaxed, intent, 2);
                if (!routes.isEmpty()) {
                    log.info("Found solution with relaxed constraints");
                    break;
                }
            }
        }

        if (routes.isEmpty()) {
            return new PlanningResult(List.of(), "约束条件过于严格，无法生成路线方案", intent);
        }

        // Validate routes against constraints
        var validatedRoutes = routes.stream()
                .map(route -> {
                    var result = constraintEngine.validate(route, constraints, intent);
                    if (result.hasHardViolations()) {
                        log.warn("Route {} has hard constraint violations", route.id());
                    }
                    return route;
                })
                .toList();

        log.info("PlanningAgent generated {} valid routes", validatedRoutes.size());
        return new PlanningResult(validatedRoutes, null, intent);
    }

    /**
     * Re-plan with partial preservation (for adjustments).
     * Keeps the prefix POIs and only re-optimizes the suffix.
     */
    public PlanningResult replan(DiscoveryAgent.DiscoveryResult discovery,
                                 UserIntent newIntent, List<Route.RouteSegment> keptPrefix,
                                 List<Constraint> additionalConstraints) {
        log.info("PlanningAgent re-planning with {} kept prefix POIs", keptPrefix.size());

        // Remove kept POIs from candidates to avoid duplicates
        var keptIds = keptPrefix.stream().map(s -> s.poi().id()).collect(Collectors.toSet());
        var remainingCandidates = discovery.candidates().stream()
                .filter(p -> !keptIds.contains(p.id()))
                .toList();

        // Create modified discovery with remaining candidates
        var modifiedDiscovery = new DiscoveryAgent.DiscoveryResult(
                remainingCandidates, discovery.categorizedPOIs(), newIntent);

        var result = plan(modifiedDiscovery, newIntent, additionalConstraints);

        // Prepend kept prefix to each route
        if (!keptPrefix.isEmpty()) {
            var mergedRoutes = result.routes().stream()
                    .map(route -> {
                        var merged = new ArrayList<>(keptPrefix);
                        merged.addAll(route.segments());
                        double cost = merged.stream().mapToDouble(s -> s.poi().avgCost()).sum();
                        double rating = merged.stream().mapToDouble(s -> s.poi().rating()).sum();
                        double travelTime = merged.stream().mapToDouble(Route.RouteSegment::travelTimeFromPrevious).sum();
                        return new Route(route.id(), route.name(), route.description(),
                                merged, cost, travelTime, rating,
                                route.optimizationGoal(), route.satisfiedConstraints(),
                                route.violatedSoftConstraints(), route.score());
                    })
                    .toList();
            return new PlanningResult(mergedRoutes, result.warning(), newIntent);
        }

        return result;
    }

    public record PlanningResult(
            List<Route> routes,
            String warning,
            UserIntent intent
    ) {
        public boolean hasRoutes() {
            return routes != null && !routes.isEmpty();
        }
    }
}

package com.meituan.route.agent;

import com.meituan.route.model.Constraint;
import com.meituan.route.model.Route;
import com.meituan.route.model.UserIntent;
import com.meituan.route.solver.ConstraintEngine;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

import java.util.*;
import java.util.stream.Collectors;

/**
 * ConstraintAgent validates routes against constraints, handles conflict resolution,
 * and triggers re-planning when constraints cannot be satisfied.
 */
@Component
public class ConstraintAgent {

    private static final Logger log = LoggerFactory.getLogger(ConstraintAgent.class);

    private final ConstraintEngine constraintEngine;

    public ConstraintAgent(ConstraintEngine constraintEngine) {
        this.constraintEngine = constraintEngine;
    }

    /**
     * Analyze a set of routes against constraints and report results.
     */
    public ConstraintReport analyze(List<Route> routes, List<Constraint> constraints, UserIntent intent) {
        log.info("ConstraintAgent analyzing {} routes against {} constraints",
                routes.size(), constraints.size());

        var routeReports = routes.stream()
                .map(route -> {
                    var result = constraintEngine.validate(route, constraints, intent);
                    double score = constraintEngine.scoreRoute(route, constraints);
                    return new RouteConstraintReport(route, result, score);
                })
                .toList();

        boolean allFeasible = routeReports.stream()
                .noneMatch(r -> r.result().hasHardViolations());

        // Best route by constraint satisfaction score
        var bestRoute = routeReports.stream()
                .max(Comparator.comparingDouble(RouteConstraintReport::score))
                .map(RouteConstraintReport::route)
                .orElse(null);

        return new ConstraintReport(routeReports, allFeasible, bestRoute, constraints);
    }

    /**
     * Parse adjustment query and extract new constraints.
     * e.g., "换家不排队的火锅" -> category=火锅, maxQueue=10
     */
    public List<Constraint> parseAdjustmentConstraints(String adjustment) {
        var constraints = new ArrayList<Constraint>();

        if (adjustment == null || adjustment.isBlank()) return constraints;

        // Check for cuisine replacements
        if (adjustment.contains("火锅")) {
            constraints.add(Constraint.category("RESTAURANT", 8));
        }
        if (adjustment.contains("日料") || adjustment.contains("日本料理")) {
            constraints.add(Constraint.category("RESTAURANT", 8));
        }

        // Queue tolerance
        if (adjustment.contains("不排队") || adjustment.contains("少排队")) {
            constraints.add(Constraint.maxQueue(10, 9));
        }

        // Rating requirement
        if (adjustment.matches(".*评分[以至少高于大于等于]*[\\d.]+.*")) {
            var matcher = java.util.regex.Pattern.compile("([\\d.]+)").matcher(adjustment);
            if (matcher.find()) {
                double rating = Double.parseDouble(matcher.group(1));
                constraints.add(Constraint.minRating(rating, 9));
            }
        }

        // Budget adjustment
        if (adjustment.contains("预算")) {
            var matcher = java.util.regex.Pattern.compile("(\\d+)").matcher(adjustment);
            if (matcher.find()) {
                double budget = Double.parseDouble(matcher.group(1));
                constraints.add(Constraint.budget(budget, 7));
            }
        }

        // Travel mode
        if (adjustment.contains("开车") || adjustment.contains("打车")) {
            constraints.add(Constraint.travelMode("DRIVING", 6));
        }
        if (adjustment.contains("走路") || adjustment.contains("步行")) {
            constraints.add(Constraint.travelMode("WALKING", 6));
        }

        return constraints;
    }

    /**
     * Generate a human-readable conflict report.
     */
    public String generateConflictReport(ConstraintReport report) {
        if (report.allFeasible()) return "所有方案均满足约束条件";

        var sb = new StringBuilder();
        sb.append("### 约束冲突报告\n\n");

        for (var routeReport : report.routeReports()) {
            if (!routeReport.result().hasHardViolations()) continue;

            sb.append("**").append(routeReport.route().name()).append("**\n");
            for (var violation : routeReport.result().violations()) {
                sb.append("- ").append(violation.message()).append("\n");
            }
            sb.append("\n");
        }

        sb.append("建议放松约束条件或选择其他路线方案。");
        return sb.toString();
    }

    public record RouteConstraintReport(Route route, ConstraintEngine.ConstraintResult result, double score) {}

    public record ConstraintReport(
            List<RouteConstraintReport> routeReports,
            boolean allFeasible,
            Route bestRoute,
            List<Constraint> constraints
    ) {}
}

package com.meituan.route.agent;

import com.meituan.route.llm.RecommendationExplainer;
import com.meituan.route.model.Route;
import com.meituan.route.model.UserIntent;
import org.springframework.stereotype.Component;

import java.util.List;

/**
 * ExplanationAgent generates natural language explanations and recommendations
 * for each route plan, highlighting differences between options.
 */
@Component
public class ExplanationAgent {

    private final RecommendationExplainer explainer;

    public ExplanationAgent(RecommendationExplainer explainer) {
        this.explainer = explainer;
    }

    /**
     * Generate explanations for a set of route plans.
     */
    public ExplanationResult explain(List<Route> routes, UserIntent intent) {
        if (routes.isEmpty()) {
            return new ExplanationResult("暂无可用方案", "没有找到满足条件的路线方案", routes, null);
        }

        var detailed = explainer.compareRoutes(routes);
        var summary = buildSummary(routes, intent);
        var comparison = explainer.compareRoutes(routes);

        return new ExplanationResult(summary, detailed, routes, comparison);
    }

    /**
     * Generate explanation for a single route (e.g., after adjustment).
     */
    public ExplanationResult explainSingle(Route route, UserIntent intent) {
        var text = explainer.explainRoute(route);
        var summary = buildSingleSummary(route);
        return new ExplanationResult(summary, text, List.of(route), text);
    }

    private String buildSummary(List<Route> routes, UserIntent intent) {
        var sb = new StringBuilder();

        String district = intent.district() != null ? intent.district() : intent.city();
        sb.append("为您规划了").append(routes.size()).append("条").append(district).append("路线方案：\n");

        for (int i = 0; i < routes.size(); i++) {
            var route = routes.get(i);
            String goalLabel = switch (route.optimizationGoal()) {
                case "BEST_EXPERIENCE" -> "体验最优";
                case "FASTEST" -> "最高效";
                case "CHEAPEST" -> "最省钱";
                default -> "方案" + (i + 1);
            };
            sb.append(i + 1).append(". ").append(goalLabel).append("：");
            sb.append(route.segments().size()).append("站 | ");
            sb.append("¥").append(String.format("%.0f", route.totalCost())).append(" | ");
            sb.append("均分").append(String.format("%.1f",
                    route.totalRating() / route.segments().size())).append("\n");
        }

        return sb.toString();
    }

    private String buildSingleSummary(Route route) {
        var names = route.segments().stream().map(s -> s.poi().name()).toList();
        return "为您更新路线：" + String.join(" → ", names);
    }

    public record ExplanationResult(
            String summary,
            String detailedExplanation,
            List<Route> routes,
            String comparisonHtml
    ) {}
}

